import React, { useState, useEffect } from 'react';

export default function AnalogClock() {
  const [now, setNow] = useState(new Date());

  useEffect(() => {
    const id = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(id);
  }, []);

  const s = now.getSeconds();
  const m = now.getMinutes();
  const h = now.getHours() % 12;
  const secDeg = s * 6;
  const minDeg = m * 6 + s * 0.1;
  const hourDeg = h * 30 + m * 0.5;

  return (
    <div>
      <svg viewBox="0 0 100 100" width="200" height="200">
        <circle cx="50" cy="50" r="48" fill="#fff" stroke="#111827" strokeWidth="2" />
        {Array.from({ length: 12 }, (_, i) => (
          <line
            key={i}
            x1="50"
            y1="6"
            x2="50"
            y2="12"
            stroke="#111827"
            strokeWidth="1.5"
            transform={`rotate(${i * 30} 50 50)`}
          />
        ))}
        <line x1="50" y1="50" x2="50" y2="26" stroke="#111827" strokeWidth="3.5" strokeLinecap="round" transform={`rotate(${hourDeg} 50 50)`} />
        <line x1="50" y1="50" x2="50" y2="16" stroke="#374151" strokeWidth="2.5" strokeLinecap="round" transform={`rotate(${minDeg} 50 50)`} />
        <line x1="50" y1="54" x2="50" y2="14" stroke="#dc2626" strokeWidth="1" strokeLinecap="round" transform={`rotate(${secDeg} 50 50)`} />
        <circle cx="50" cy="50" r="2" fill="#111827" />
      </svg>
      <p style={{ fontFamily: 'monospace' }}>{now.toLocaleTimeString()}</p>
    </div>
  );
}

