import { Component, OnInit, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-analog-clock',
  template: `
    <div>
      <svg viewBox="0 0 100 100" width="200" height="200">
        <circle cx="50" cy="50" r="48" fill="#fff" stroke="#111827" stroke-width="2"></circle>
        <line
          *ngFor="let d of marks"
          x1="50" y1="6" x2="50" y2="12"
          stroke="#111827" stroke-width="1.5"
          [attr.transform]="'rotate(' + d + ' 50 50)'"
        ></line>
        <line x1="50" y1="50" x2="50" y2="26" stroke="#111827" stroke-width="3.5" stroke-linecap="round" [attr.transform]="'rotate(' + hourDeg + ' 50 50)'"></line>
        <line x1="50" y1="50" x2="50" y2="16" stroke="#374151" stroke-width="2.5" stroke-linecap="round" [attr.transform]="'rotate(' + minDeg + ' 50 50)'"></line>
        <line x1="50" y1="54" x2="50" y2="14" stroke="#dc2626" stroke-width="1" stroke-linecap="round" [attr.transform]="'rotate(' + secDeg + ' 50 50)'"></line>
        <circle cx="50" cy="50" r="2" fill="#111827"></circle>
      </svg>
      <p style="font-family: monospace;">{{ label }}</p>
    </div>
  `,
})
export class AnalogClockComponent implements OnInit, OnDestroy {
  now = new Date();
  marks = [0, 30, 60, 90, 120, 150, 180, 210, 240, 270, 300, 330];
  private id: any = null;

  ngOnInit(): void {
    this.id = setInterval(() => {
      this.now = new Date();
    }, 1000);
  }

  ngOnDestroy(): void {
    clearInterval(this.id);
  }

  get hourDeg(): number {
    return (this.now.getHours() % 12) * 30 + this.now.getMinutes() * 0.5;
  }

  get minDeg(): number {
    return this.now.getMinutes() * 6 + this.now.getSeconds() * 0.1;
  }

  get secDeg(): number {
    return this.now.getSeconds() * 6;
  }

  get label(): string {
    return this.now.toLocaleTimeString();
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Analog Clock Demo</h1>
      <app-analog-clock></app-analog-clock>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, AnalogClockComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
